library(dplyr)library(ggplot2)#library(rjags)ver <- "v1";setwd("~/research/Song_Liang/EXCAM/andrew")agecat <- 1;# two times of observations at different age; # agecat = 1 or 2;#load data;#directly load Bruce preprocessed data for first observation;hh_obs <- readRDS("observational_data_tp1_processed.RDS")#hh_obs <- readRDS("~/stat/EXCAM/Bruce/Behavior Observation Data/Processed Data/observational_data_tp2_processed.RDS")#table(hh_obs$name)hh_obs$name <- toupper(hh_obs$name)extract.obs_id <- function(name){  paste(strsplit(name,c("[-._]+"))[[1]][2:3],collapse = "_")}hh_obs$obs_id <- sapply(hh_obs$name,extract.obs_id)hh_obs$Start.datetime <- as.POSIXlt(strptime(hh_obs$Start.datetime,"%m/%d/%Y %H:%M:%S"));hh_obs$End.datetime <- as.POSIXlt(strptime(hh_obs$End.datetime,"%m/%d/%Y %H:%M:%S"));colnames(hh_obs)[colnames(hh_obs)=='Ending.time'] <- 'End.time'#simplify the items;hh_obs$item <- tolower(hh_obs$item)hh_obs$item_simple <- hh_obs$itemhh_obs$item_simple[which(hh_obs$item %in% c("carried-mom arms","carried-mom back"))] <- "carried-mom"hh_obs$item_simple[which(hh_obs$item %in% c("carried-other arms","carried-other back"))] <- "carried-other"hh_obs$item_simple[which(hh_obs$item %in% c("drinking-breastmilk","drinking-other","drinking-water"))] <- "drinking"hh_obs$item_simple[which(hh_obs$item %in% c("eating-injera", "eating-other",  "eating-raw plant"))] <- "eaing"hh_obs$item_simple[which(hh_obs$item %in% c("mouthing-child hand", "mouthing-mom hand",  "mouthing-other adult hand"))] <- "mouthing-others hand"table(hh_obs$item_simple)table(hh_obs$category)hh_obs$category <- as.character(hh_obs$category)hh_obs$category[hh_obs$category=='mistake'] <- 'Mistake'hh_obs$category[! (hh_obs$category %in% c('Location', 'Compartment', 'Activity', 'Mistake'))] <- 'Event'table(hh_obs$category)hh_obs <- hh_obs[order(hh_obs$hh_id,hh_obs$Start.datetime),]dat.loc <- subset(hh_obs, category=='Location', select=c(hh_id, obs_id, Start.datetime, End.datetime, Start.time, End.time, item_simple, item))dat.com <- subset(hh_obs, category=='Compartment', select=c(hh_id, obs_id, Start.datetime, End.datetime, Start.time, End.time, item_simple, item))dat.act <- subset(hh_obs, category=='Activity', select=c(hh_id, obs_id, Start.datetime, End.datetime, Start.time, End.time, item_simple, item))dat.evt <- subset(hh_obs, category=='Event', select=c(hh_id, obs_id, Start.datetime, End.datetime, Start.time, End.time, item_simple, item))################################# check time gaps for each layer################################# check large time gaps in location. We compare such gaps with time intervals of compartments. dat.loc$gap <- NAfor(i in 2:nrow(dat.loc))  if(dat.loc$obs_id[i] == dat.loc$obs_id[i-1]) dat.loc$gap[i] <- dat.loc$Start.time[i] - dat.loc$End.time[i-1]hist(dat.loc$gap[!is.na(dat.loc$gap) & dat.loc$gap>10], breaks=50)# if lag is more than 5 seconds, take a further lookcheck.id <- unique(dat.loc$obs_id[!is.na(dat.loc$gap) & dat.loc$gap>10]) check <- subset(dat.loc, obs_id %in% check.id)# examine entries with large gaps# BALLO_014, BALLO_082, MERI_091, MERI_111, FAYO_132 had large gaps in compartment.# All gaps seem to be accidental error, as they are all covered by consecutive compartment time intervals.obs.id = 'BALLO_082'check.loc = subset(dat.loc, obs_id==obs.id)check.com = subset(dat.com, obs_id==obs.id)# check large time gaps in compartment. We compare such gaps with time intervals of activities. dat.com$gap <- NAfor(i in 2:nrow(dat.com))  if(dat.com$obs_id[i] == dat.com$obs_id[i-1]) dat.com$gap[i] <- dat.com$Start.time[i] - dat.com$End.time[i-1]hist(dat.com$gap[!is.na(dat.com$gap) & dat.com$gap>50], breaks=50)check.id <- unique(dat.com$obs_id[!is.na(dat.com$gap) & dat.com$gap>50]) check <- subset(dat.com, obs_id %in% check.id)# FAYO_025, FAYO_059, FAYO_075, BALLO_114 had large gaps in compartment.# All gaps seem to be accidental error, as they are all covered by consecutive activity time intervals.obs.id = 'BALLO_114'check.com = subset(dat.com, obs_id==obs.id)check.act = subset(dat.act, obs_id==obs.id)# check large time gaps in compartment. We compare such gaps with time intervals of activities. dat.act$gap <- NAfor(i in 2:nrow(dat.act))  if(dat.act$obs_id[i] == dat.act$obs_id[i-1]) dat.act$gap[i] <- dat.act$Start.time[i] - dat.act$End.time[i-1]hist(dat.act$gap[!is.na(dat.act$gap) & dat.act$gap>50], breaks=50)check.id <- unique(dat.act$obs_id[!is.na(dat.act$gap) & dat.act$gap>50]) check <- subset(dat.act, obs_id %in% check.id)# FAYO_001, FAYO_009, FAYO_010, FAYO_013, FAYO_016, BALLO_106 had large gaps in compartment.# For FAYO, nearly all gaps occurred during drinking breast milk. We may simply bridge most gaps as they are most likely drinking breast milk.# For BALLO_106, it seems to an accidental error, but it's not clear whether the gap was associated with sleeping or awake.obs.id = 'BALLO_106'check.com = subset(dat.com, obs_id==obs.id)check.act = subset(dat.act, obs_id==obs.id)check.evt = subset(dat.evt, obs_id==obs.id)